mapper.select:
SELECT r.id, e.name AS name, c.course_name AS courseName, r.submitted_at AS submittedAt, r.score, r.evaluation_status AS evaluationStatus FROM tc_lab_report r LEFT JOIN tc_plan_detail pd ON pd.id = r.schedule_id LEFT JOIN tc_experiment e ON e.id = pd.experiment_id LEFT JOIN tc_course c ON c.id = pd.course_id WHERE r.student_id = #{studentId}
AND r.evaluation_status = #{status}
AND pd.course_id = #{courseId}
ORDER BY r.create_time DESC

SELECT DISTINCT c.id, c.course_name AS courseName, t.name AS teacherName,
CASE WHEN COUNT(r.id) > 0 THEN 1 ELSE 0 END AS status FROM tc_lab_report r INNER JOIN tc_plan_detail pd ON pd.id = r.schedule_id INNER JOIN tc_course c ON c.id = pd.course_id LEFT JOIN tc_teacher t ON t.id = c.teacher_id WHERE r.student_id = #{studentId}
AND r.evaluation_status = #{status}
GROUP BY c.id, c.course_name, t.name
